const { NodeSDK } = require('@opentelemetry/sdk-node');
const { getNodeAutoInstrumentations } = require('@opentelemetry/auto-instrumentations-node');
const { Resource } = require('@opentelemetry/resources');
const { ATTR_SERVICE_NAME, ATTR_SERVICE_VERSION } = require('@opentelemetry/semantic-conventions');
const { ConsoleSpanExporter } = require('@opentelemetry/sdk-trace-node');
const { OTLPTraceExporter } = require('@opentelemetry/exporter-trace-otlp-http');
const { trace, context, propagation } = require('@opentelemetry/api');

let sdk;

/**
 * Initialize OpenTelemetry tracing for a service
 * @param {string} serviceName - Name of the service
 * @param {string} serviceVersion - Version of the service
 */
function initTracing(serviceName, serviceVersion = '1.0.0') {
  const resource = new Resource({
    [ATTR_SERVICE_NAME]: serviceName,
    [ATTR_SERVICE_VERSION]: serviceVersion,
  });

  // Configure trace exporter based on environment
  let traceExporter;
  const honeycombApiKey = process.env.HONEYCOMB_API_KEY;

  if (honeycombApiKey) {
    // Send traces to Honeycomb
    traceExporter = new OTLPTraceExporter({
      url: 'https://api.honeycomb.io/v1/traces',
      headers: {
        'x-honeycomb-team': honeycombApiKey,
      },
    });
    console.log(`[${serviceName}] OpenTelemetry configured for Honeycomb`);
  } else {
    // Fallback to console for debugging
    traceExporter = new ConsoleSpanExporter();
    console.log(`[${serviceName}] OpenTelemetry configured for console output (set HONEYCOMB_API_KEY to send to Honeycomb)`);
  }

  sdk = new NodeSDK({
    resource: resource,
    traceExporter: traceExporter,
    instrumentations: [
      getNodeAutoInstrumentations({
        '@opentelemetry/instrumentation-fs': {
          enabled: false, // Disable noisy filesystem instrumentation
        },
      }),
    ],
  });

  sdk.start();
  console.log(`[${serviceName}] OpenTelemetry tracing initialized`);

  // Graceful shutdown
  process.on('SIGTERM', async () => {
    try {
      await sdk.shutdown();
      console.log(`[${serviceName}] OpenTelemetry SDK shut down successfully`);
    } catch (error) {
      console.error(`[${serviceName}] Error shutting down OpenTelemetry SDK`, error);
    } finally {
      process.exit(0);
    }
  });
}

/**
 * Get the tracer for the current service
 * @param {string} tracerName - Name of the tracer (usually service name)
 * @returns {Tracer}
 */
function getTracer(tracerName) {
  return trace.getTracer(tracerName);
}

/**
 * Get the active span in the current context
 * @returns {Span | undefined}
 */
function getActiveSpan() {
  return trace.getActiveSpan();
}

/**
 * Add custom attributes to the active span
 * @param {Object} attributes - Key-value pairs of attributes to add
 */
function addSpanAttributes(attributes) {
  const span = trace.getActiveSpan();
  if (span) {
    span.setAttributes(attributes);
  }
}

/**
 * Set span status to error with optional message
 * @param {string} errorMessage - Error message to set
 * @param {Error} error - Optional error object
 */
function setSpanError(errorMessage, error = null) {
  const span = trace.getActiveSpan();
  if (span) {
    span.setStatus({
      code: 2, // ERROR
      message: errorMessage,
    });
    if (error) {
      span.recordException(error);
    }
  }
}

/**
 * Extract trace context from HTTP headers
 * @param {Object} headers - HTTP headers object
 * @returns {Context}
 */
function extractContext(headers) {
  return propagation.extract(context.active(), headers);
}

/**
 * Inject trace context into HTTP headers
 * @param {Context} ctx - Context to inject
 * @param {Object} headers - Headers object to inject into
 */
function injectContext(ctx, headers) {
  propagation.inject(ctx, headers);
}

/**
 * Create a new span with custom attributes
 * @param {string} spanName - Name of the span
 * @param {Object} attributes - Custom attributes for the span
 * @param {Function} fn - Function to execute within the span
 * @returns {Promise<any>}
 */
async function createSpan(spanName, attributes, fn) {
  const tracer = trace.getTracer('default');
  const span = tracer.startSpan(spanName);

  if (attributes) {
    span.setAttributes(attributes);
  }

  try {
    const result = await context.with(trace.setSpan(context.active(), span), fn);
    span.end();
    return result;
  } catch (error) {
    span.setStatus({
      code: 2, // ERROR
      message: error.message,
    });
    span.recordException(error);
    span.end();
    throw error;
  }
}

module.exports = {
  initTracing,
  getTracer,
  getActiveSpan,
  addSpanAttributes,
  setSpanError,
  extractContext,
  injectContext,
  createSpan,
  trace,
  context,
  propagation,
};
